%%ExamplePlotwithCalculationsandAnnotations
%Thisscriptplots the tank levelresponseand calculates:
%steady-state value, percent error, time constant (tau)

t = out.tout;
y = out.y;

figure;
plot(t, y, 'LineWidth', 1.5);
grid on;
title('Example: Tank Level Response with Annotations');
xlabel('Time (s)');

hold on;

%% --- Steady-State Value ---
y_ss = y(end);

% Percent error for 1-inch step input
error = 1 - y_ss;
percent_error = error * 100;

% Mark steady-state point
plot(t(end), y_ss, 'ro');

% Label steady-state and error
text(t(end)*0.6, y_ss*0.95, ...
    sprintf('y_{ss} = %.3f in\nError = %.2f%%', y_ss, percent_error), ...
    'FontSize', 10);

%% --- Time Constant (tau) ---
% tau = time when output reaches 63.2% of steady-state value
y_tau = 0.632 * y_ss;

% Find closest time index
[~, idx] = min(abs(y - y_tau));
t_tau = t(idx);

% Adjust for step time (assumes step at t = 1 s)
tau = t_tau - 1;

% Mark tau point
plot(t_tau, y_tau, 'ro');

% Label tau
text(t_tau + 0.5, y_tau, ...
    sprintf('\tau \approx %.2f s', tau), ...
    'FontSize', 10);

hold off;

